fn execute(input: &serde_json::Value) -> serde_json::Value {
    let count = input.get("count").and_then(|v| v.as_f64()).unwrap_or(0.0) as i64;
    serde_json::json!({
        "tag": "div",
        "props": {"class": "counter"},
        "children": [
            {"tag": "h1", "props": {"class": "counter-value"}, "children": [{"$text": format!("Count: {}", count)}]},
            {"tag": "div", "props": {"class": "counter-buttons"}, "children": [
                {"tag": "button", "props": {"class": "btn btn-dec", "onClick": {"$event": "decrement"}}, "children": [{"$text": "-"}]},
                {"tag": "button", "props": {"class": "btn btn-inc", "onClick": {"$event": "increment"}}, "children": [{"$text": "+"}]},
                {"tag": "button", "props": {"class": "btn btn-reset", "onClick": {"$event": "reset"}}, "children": [{"$text": "Reset"}]}
            ]}
        ]
    })
}
